1	<script>
2		// Probe angle in degrees, 0 = pointing right, increasing counterclockwise.
3		let value = $state(90);
4		let dragging = false;
5	
6		const candidatesDef = [
7			{ id: 'c1', angle: 20 },
8			{ id: 'c2', angle: 70 },
9			{ id: 'c3', angle: 110 },
10			{ id: 'c4', angle: 160 }
11		];
12	
13		const cx = 130;
14		const cy = 130;
15	
16		function point(angleDeg, radius) {
17			const rad = (angleDeg * Math.PI) / 180;
18			return { x: cx + radius * Math.cos(rad), y: cy - radius * Math.sin(rad) };
19		}
20	
21		function clamp(v) {
22			return Math.min(360, Math.max(0, v));
23		}
24	
25		let probeTip = $derived(point(value, 100));
26		let probeLabel = $derived(point(value, 122));
27	
28		let scores = $derived(
29			candidatesDef.map((c) => {
30				const raw = Math.cos(((value - c.angle) * Math.PI) / 180);
31				const top = raw >= 0 ? 50 - raw * 50 : 50;
32				const height = Math.abs(raw) * 50;
33				return { id: c.id, angle: c.angle, score: raw, top, height };
34			})
35		);
36	
37		let bestId = $derived.by(() => {
38			let best = scores[0];
39			for (const s of scores) {
40				if (s.score > best.score) best = s;
41			}
42			return best.id;
43		});
44	
45		function angleFromPointer(e) {
46			const rect = e.currentTarget.getBoundingClientRect();
47			const centerX = rect.left + rect.width / 2;
48			const centerY = rect.top + rect.height / 2;
49			const dx = e.clientX - centerX;
50			const dy = e.clientY - centerY;
51			let deg = (Math.atan2(-dy, dx) * 180) / Math.PI;
52			if (deg < 0) deg += 360;
53			value = Math.round(deg);
54		}
55	
56		function handlePointerDown(e) {
57			e.currentTarget.setPointerCapture(e.pointerId);
58			dragging = true;
59			angleFromPointer(e);
60		}
61	
62		function handlePointerMove(e) {
63			if (!dragging) return;
64			angleFromPointer(e);
65		}
66	
67		function handlePointerUp(e) {
68			dragging = false;
69			try {
70				e.currentTarget.releasePointerCapture(e.pointerId);
71			} catch (err) {
72				// pointer capture already released, ignore
73			}
74		}
75	
76		function handleKeydown(e) {
77			const step = 5;
78			let handled = true;
79			switch (e.key) {
80				case 'ArrowRight':
81				case 'ArrowUp':
82					value = clamp(value + step);
83					break;
84				case 'ArrowLeft':
85				case 'ArrowDown':
86					value = clamp(value - step);
87					break;
88				case 'Home':
89					value = 0;
90					break;
91				case 'End':
92					value = 360;
93					break;
94				default:
95					handled = false;
96			}
97			if (handled) e.preventDefault();
98		}
99	</script>
