134							dominant-baseline="middle"
135							style="fill: var(--color-text); font-family: var(--font-mono); font-size: 11px"
136						>{c.id}</text>
137					{/each}
138	
139					<line
140						x1={cx}
141						y1={cy}
142						x2={probeTip.x}
143						y2={probeTip.y}
144						style="stroke: var(--data-heat); stroke-width: 4"
145						marker-end="url(#dot-alignment-arrow-heat)"
146					/>
147					<text
148						x={probeLabel.x}
149						y={probeLabel.y}
150						text-anchor="middle"
151						dominant-baseline="middle"
152						style="fill: var(--color-text); font-family: var(--font-mono); font-size: 12px; font-weight: 600"
153					>probe {value}&deg;</text>
154				</svg>
155	
156				<div
157					class="slider"
158					role="slider"
159					tabindex="0"
160					aria-label="Probe angle in degrees"
161					aria-valuemin="0"
162					aria-valuemax="360"
163					aria-valuenow={value}
164					onpointerdown={handlePointerDown}
165					onpointermove={handlePointerMove}
166					onpointerup={handlePointerUp}
167					onpointercancel={handlePointerUp}
168					onkeydown={handleKeydown}
169				></div>
170			</div>
171	
172			<div class="scores">
173				{#each scores as s (s.id)}
174					<div class="score-col" class:best={s.id === bestId}>
